    public double Recall { get; set; }
    public double F1Score { get; set; }
}

using Microsoft.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

public class TicketClassifierService
{
    private readonly MLContext _mlContext;
    private readonly ITransformer _model;
    private readonly PredictionEngine<TicketData, TicketPrediction> _predictionEngine;
    private readonly IDataView _trainingData;
    private readonly string[] _categoryNames;

    public TicketClassifierService(string dataPath)
    {
        _mlContext = new MLContext(seed: 42);
        _trainingData = _mlContext.Data.LoadFromTextFile<TicketData>(
            dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        _model = TrainModel();
        _predictionEngine = _mlContext.Model.CreatePredictionEngine<TicketData, TicketPrediction>(_model);

        // Extract ordered label names so we can map Score[] to category names.
        var schema = _model.GetOutputSchema(_trainingData.Schema);
        var labelBuffer = new VBuffer<ReadOnlyMemory<char>>();
        schema["Score"].GetSlotNames(ref labelBuffer);
        _categoryNames = labelBuffer.DenseValues().Select(v => v.ToString()).ToArray();
    }

    private ITransformer TrainModel()
    {
        // Combine Subject + Description into a single text feature, featurize it,
        // and concatenate with the numeric Priority column.
        var pipeline = _mlContext.Transforms.Conversion
                .MapValueToKey("Label", nameof(TicketData.Category))
            .Append(_mlContext.Transforms.Text.FeaturizeText(
                "SubjectFeaturized", nameof(TicketData.Subject)))
            .Append(_mlContext.Transforms.Text.FeaturizeText(
                "DescriptionFeaturized", nameof(TicketData.Description)))
            .Append(_mlContext.Transforms.Concatenate(
                "Features", "SubjectFeaturized", "DescriptionFeaturized", nameof(TicketData.Priority)))
            .Append(_mlContext.MulticlassClassification.Trainers
                .SdcaMaximumEntropy("Label", "Features"))
            .Append(_mlContext.Transforms.Conversion
                .MapKeyToValue("PredictedLabel"));

        return pipeline.Fit(_trainingData);
    }

    public PredictionResponse Predict(TicketRequest request)
    {
        var input = new TicketData
        {
            Subject = request.Subject,
            Description = request.Description,
            Priority = request.Priority
        };

        var prediction = _predictionEngine.Predict(input);

        var confidence = new Dictionary<string, float>();
        for (var i = 0; i < _categoryNames.Length; i++)
        {
            confidence[_categoryNames[i]] = prediction.Score[i];
        }

        return new PredictionResponse
        {
            PredictedCategory = prediction.PredictedCategory,
            Confidence = confidence
        };
    }

    public EvaluationResponse Evaluate()
    {
        // Use cross-validation to get realistic metrics from the small dataset.
        var pipeline = _mlContext.Transforms.Conversion
                .MapValueToKey("Label", nameof(TicketData.Category))
            .Append(_mlContext.Transforms.Text.FeaturizeText(
                "SubjectFeaturized", nameof(TicketData.Subject)))
            .Append(_mlContext.Transforms.Text.FeaturizeText(
                "DescriptionFeaturized", nameof(TicketData.Description)))
            .Append(_mlContext.Transforms.Concatenate(
                "Features", "SubjectFeaturized", "DescriptionFeaturized", nameof(TicketData.Priority)))
            .Append(_mlContext.MulticlassClassification.Trainers
                .SdcaMaximumEntropy("Label", "Features"))
            .Append(_mlContext.Transforms.Conversion
                .MapKeyToValue("PredictedLabel"));

        var cvResults = _mlContext.MulticlassClassification
            .CrossValidate(_trainingData, pipeline, numberOfFolds: 5, labelColumnName: "Label");

        var avgMicro = (float)cvResults.Average(r => r.Metrics.MicroAccuracy);
        var avgMacro = (float)cvResults.Average(r => r.Metrics.MacroAccuracy);
        var avgLogLoss = (float)cvResults.Average(r => r.Metrics.LogLoss);
        var avgLogLossReduction = (float)cvResults.Average(r => r.Metrics.LogLossReduction);

