        var fullPredictions = _model.Transform(_trainingData);
        var fullMetrics = _mlContext.MulticlassClassification
            .Evaluate(fullPredictions, labelColumnName: "Label");

        var perCategory = new List<CategoryMetric>();
        for (var i = 0; i < fullMetrics.PerClassLogLoss.Count; i++)
        {
            var cm = fullMetrics.ConfusionMatrix;
            perCategory.Add(new CategoryMetric
            {
                Category = _categoryNames[i],
                Precision = cm.PerClassPrecision[i],
                Recall = cm.PerClassRecall[i],
                F1Score = 2 * cm.PerClassPrecision[i] * cm.PerClassRecall[i]
                    / (cm.PerClassPrecision[i] + cm.PerClassRecall[i])
            });
        }

        return new EvaluationResponse
        {
            MicroAccuracy = avgMicro,
            MacroAccuracy = avgMacro,
            LogLoss = avgLogLoss,
            LogLossReduction = avgLogLossReduction,
            PerCategoryMetrics = perCategory
        };
    }
}

